import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, Send, Download } from 'lucide-react';
import { getPresupuesto, createPresupuesto, updatePresupuesto, getClientes, convertirAOrden } from '../../services/api';
import { formatCurrency, formasPago } from '../../utils/formatters';
import Loading from '../common/Loading';

export default function PresupuestoForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [clientes, setClientes] = useState([]);

  const [form, setForm] = useState({
    cliente_id: '', material: '', color_tipo: '', espesor: '', frente: '',
    terminacion: '', bacha: '', anafe: '', perforaciones: '',
    subtotal: 0, usd_referencia: 0, envio: 0, total: 0,
    forma_pago: '', validez: '10 días', entrega_aproximada: '',
    fecha_estimada_entrega: '', observaciones: '',
  });

  useEffect(() => {
    getClientes().then((res) => setClientes(res.data));
    if (id) {
      getPresupuesto(id).then((res) => {
        const d = res.data;
        setForm({
          cliente_id: d.cliente_id || '',
          material: d.material || '', color_tipo: d.color_tipo || '', espesor: d.espesor || '',
          frente: d.frente || '', terminacion: d.terminacion || '', bacha: d.bacha || '',
          anafe: d.anafe || '', perforaciones: d.perforaciones || '',
          subtotal: d.subtotal || 0, usd_referencia: d.usd_referencia || 0, envio: d.envio || 0, total: d.total || 0,
          forma_pago: d.forma_pago || '', validez: d.validez || '10 días',
          entrega_aproximada: d.entrega_aproximada || '',
          fecha_estimada_entrega: d.fecha_estimada_entrega ? d.fecha_estimada_entrega.slice(0, 10) : '',
          observaciones: d.observaciones || '',
        });
        setLoading(false);
      });
    }
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        cliente_id: Number(form.cliente_id),
        subtotal: Number(form.subtotal),
        usd_referencia: Number(form.usd_referencia),
        envio: Number(form.envio),
        total: Number(form.total),
        fecha_estimada_entrega: form.fecha_estimada_entrega || null,
      };
      if (isEdit) {
        await updatePresupuesto(id, payload);
      } else {
        await createPresupuesto(payload);
      }
      navigate('/presupuestos');
    } catch (err) {
      alert('Error al guardar');
    } finally {
      setSaving(false);
    }
  };

  const handleConvertir = async () => {
    if (!window.confirm('¿Convertir este presupuesto aprobado en orden de trabajo?')) return;
    try {
      await convertirAOrden(id);
      navigate('/ordenes');
    } catch (err) {
      alert(err.response?.data?.detail || 'Error');
    }
  };

  if (loading) return <Loading />;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>{isEdit ? 'Editar Presupuesto' : 'Nuevo Presupuesto'}</h1>
        <div style={{ display: 'flex', gap: 8 }}>
          {isEdit && (
            <>
              <button className="btn btn-success" onClick={handleConvertir}><Send size={16} /> Convertir a Orden</button>
            </>
          )}
        </div>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={{ display: 'grid', gap: 20, maxWidth: 900 }}>
          {/* Cliente */}
          <div className="card">
            <h3 className="section-title">Datos del Cliente</h3>
            <div className="form-group">
              <label>Cliente *</label>
              <select className="input" required value={form.cliente_id} onChange={(e) => setForm({ ...form, cliente_id: e.target.value })}>
                <option value="">Seleccionar cliente...</option>
                {clientes.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
              </select>
            </div>
          </div>

          {/* Especificaciones */}
          <div className="card">
            <h3 className="section-title">Especificaciones</h3>
            <div className="form-row">
              <div className="form-group"><label>Material</label><input className="input" value={form.material} onChange={(e) => setForm({ ...form, material: e.target.value })} /></div>
              <div className="form-group"><label>Color / Tipo</label><input className="input" value={form.color_tipo} onChange={(e) => setForm({ ...form, color_tipo: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Espesor</label><input className="input" value={form.espesor} onChange={(e) => setForm({ ...form, espesor: e.target.value })} /></div>
              <div className="form-group"><label>Frente</label><input className="input" value={form.frente} onChange={(e) => setForm({ ...form, frente: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Terminación</label><input className="input" value={form.terminacion} onChange={(e) => setForm({ ...form, terminacion: e.target.value })} /></div>
              <div className="form-group"><label>Bacha</label><input className="input" value={form.bacha} onChange={(e) => setForm({ ...form, bacha: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Anafe</label><input className="input" value={form.anafe} onChange={(e) => setForm({ ...form, anafe: e.target.value })} /></div>
              <div className="form-group"><label>Perforaciones</label><input className="input" value={form.perforaciones} onChange={(e) => setForm({ ...form, perforaciones: e.target.value })} /></div>
            </div>
          </div>

          {/* Económico */}
          <div className="card">
            <h3 className="section-title">Resumen Económico</h3>
            <div className="form-row">
              <div className="form-group"><label>Subtotal ($)</label><input className="input" type="number" step="0.01" value={form.subtotal} onChange={(e) => setForm({ ...form, subtotal: e.target.value })} /></div>
              <div className="form-group"><label>U$S Referencia</label><input className="input" type="number" step="0.01" value={form.usd_referencia} onChange={(e) => setForm({ ...form, usd_referencia: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Envío ($)</label><input className="input" type="number" step="0.01" value={form.envio} onChange={(e) => setForm({ ...form, envio: e.target.value })} /></div>
              <div className="form-group"><label>Total ($)</label><input className="input" type="number" step="0.01" value={form.total} onChange={(e) => setForm({ ...form, total: e.target.value })} /></div>
            </div>
            <div className="form-group">
              <label>Forma de Pago</label>
              <select className="input" value={form.forma_pago} onChange={(e) => setForm({ ...form, forma_pago: e.target.value })}>
                <option value="">Seleccionar...</option>
                {formasPago.map((f) => <option key={f} value={f}>{f}</option>)}
              </select>
            </div>
          </div>

          {/* Comercial */}
          <div className="card">
            <h3 className="section-title">Información Comercial</h3>
            <div className="form-row">
              <div className="form-group"><label>Validez</label><input className="input" value={form.validez} onChange={(e) => setForm({ ...form, validez: e.target.value })} /></div>
              <div className="form-group"><label>Entrega aproximada</label><input className="input" value={form.entrega_aproximada} onChange={(e) => setForm({ ...form, entrega_aproximada: e.target.value })} /></div>
            </div>
            <div className="form-group">
              <label>Fecha estimada de entrega</label>
              <input className="input" type="date" value={form.fecha_estimada_entrega} onChange={(e) => setForm({ ...form, fecha_estimada_entrega: e.target.value })} />
            </div>
          </div>

          {/* Observaciones */}
          <div className="card">
            <h3 className="section-title">Observaciones</h3>
            <div className="form-group">
              <textarea className="input" rows={4} value={form.observaciones} onChange={(e) => setForm({ ...form, observaciones: e.target.value })} />
            </div>
          </div>

          <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
            <button type="button" className="btn btn-outline" onClick={() => navigate('/presupuestos')}>Cancelar</button>
            <button type="submit" className="btn btn-primary" disabled={saving}>
              <Save size={16} /> {saving ? 'Guardando...' : (isEdit ? 'Actualizar' : 'Crear Presupuesto')}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}
